// src/components/SelectLLMModel.jsx

import React, { useState } from 'react';

function SelectLLMModel({ setTriples, setOntologies }) {  // Add setOntologies prop
  const [model, setModel] = useState('gpt-3.5-turbo');
  const [isLoading, setIsLoading] = useState(false);

  const handleModelChange = (modelName) => {
    setModel(modelName);
  };

  const handleRunClick = async () => {
    setIsLoading(true);

    try {
      const res = await fetch('http://127.0.0.1:8000/api/run-llm-model/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ model }),
      });

      const data = await res.json();
      setTriples(data.triples);  // Update triples state
      setOntologies(data.ontologies);  // Update ontologies state
    } catch (error) {
      console.error('An error occurred while running the model:', error);
    }

    setIsLoading(false);
  };

  return (
    <div className="bg-gray-800 bg-opacity-50 backdrop-blur-lg text-white p-6 rounded-lg shadow-md w-full flex flex-col items-center border border-white border-opacity-10">
      <h2 className="text-lg font-bold mb-4 text-center">Select LLM Model</h2>
      <div className="flex flex-col w-full space-y-4">
        <div className="flex items-center justify-between">
          <span>ChatGPT 3.5 Turbo</span>
          <button
            className={`w-12 h-6 flex items-center bg-gray-600 rounded-full p-1 cursor-pointer ${model === 'gpt-3.5-turbo' ? 'bg-orange-500' : 'bg-blue-500'}`}
            onClick={() => handleModelChange('gpt-3.5-turbo')}
          >
            <div
              className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${model === 'gpt-3.5-turbo' ? 'translate-x-6' : ''}`}
            />
          </button>
        </div>
        <div className="flex items-center justify-between">
          <span>ChatGPT 4o Mini</span>
          <button
            className={`w-12 h-6 flex items-center bg-gray-600 rounded-full p-1 cursor-pointer ${model === 'gpt-4o-mini' ? 'bg-orange-500' : 'bg-blue-500'}`}
            onClick={() => handleModelChange('gpt-4o-mini')}
          >
            <div
              className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${model === 'gpt-4o-mini' ? 'translate-x-6' : ''}`}
            />
          </button>
        </div>
        <div className="flex items-center justify-between">
          <span>Ollama LLaMA 3.1</span>
          <button
            className={`w-12 h-6 flex items-center bg-gray-600 rounded-full p-1 cursor-pointer ${model === 'ollama-llama-3.1' ? 'bg-orange-500' : 'bg-blue-500'}`}
            onClick={() => handleModelChange('ollama-llama-3.1')}
          >
            <div
              className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${model === 'ollama-llama-3.1' ? 'translate-x-6' : ''}`}
            />
          </button>
        </div>
      </div>
      <button
        className={`mt-6 bg-white text-gray-800 font-bold py-2 px-6 rounded-full shadow-md ${isLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-gray-200'}`}
        onClick={handleRunClick}
        disabled={isLoading}
      >
        {isLoading ? 'Running...' : 'Run'}
      </button>
    </div>
  );
}

export default SelectLLMModel;
