// src/components/SelectEmbeddingModel.jsx

import React, { useState } from 'react';

function SelectEmbeddingModel() {
  const [model, setModel] = useState('text-embedding-ada-002');
  const [isLoading, setIsLoading] = useState(false);

  const handleModelChange = (modelName) => {
    setModel(modelName);
  };

  const handleRunClick = async () => {
    setIsLoading(true);

    try {
      const res = await fetch('http://127.0.0.1:8000/api/run-embedding-model/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ model }),
      });

      await res.json();  // You can handle the response if necessary, but we won't display it
    } catch (error) {
      console.error('An error occurred while running the model:', error);
    }

    setIsLoading(false);
  };

  return (
    <div className="bg-gray-800 bg-opacity-50 backdrop-blur-lg text-white p-6 rounded-lg shadow-md w-full flex flex-col items-center border border-white border-opacity-10">
      <h2 className="text-lg font-bold mb-4 text-center">Select Embedding Model</h2>
      <div className="flex flex-col w-full space-y-4">
        <div className="flex items-center justify-between">
          <span>Text Embedding ADA 002</span>
          <button
            className={`w-12 h-6 flex items-center bg-gray-600 rounded-full p-1 cursor-pointer ${model === 'text-embedding-ada-002' ? 'bg-orange-500' : 'bg-blue-500'}`}
            onClick={() => handleModelChange('text-embedding-ada-002')}
          >
            <div
              className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${model === 'text-embedding-ada-002' ? 'translate-x-6' : ''}`}
            />
          </button>
        </div>
        <div className="flex items-center justify-between">
          <span>Text Embedding 3 Small</span>
          <button
            className={`w-12 h-6 flex items-center bg-gray-600 rounded-full p-1 cursor-pointer ${model === 'text-embedding-3-small' ? 'bg-orange-500' : 'bg-blue-500'}`}
            onClick={() => handleModelChange('text-embedding-3-small')}
          >
            <div
              className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${model === 'text-embedding-3-small' ? 'translate-x-6' : ''}`}
            />
          </button>
        </div>
        <div className="flex items-center justify-between">
          <span>Text Embedding 3 Large</span>
          <button
            className={`w-12 h-6 flex items-center bg-gray-600 rounded-full p-1 cursor-pointer ${model === 'text-embedding-3-large' ? 'bg-orange-500' : 'bg-blue-500'}`}
            onClick={() => handleModelChange('text-embedding-3-large')}
          >
            <div
              className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${model === 'text-embedding-3-large' ? 'translate-x-6' : ''}`}
            />
          </button>
        </div>
      </div>
      <button
        className={`mt-6 bg-white text-gray-800 font-bold py-2 px-6 rounded-full shadow-md ${isLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-gray-200'}`}
        onClick={handleRunClick}
        disabled={isLoading}
      >
        {isLoading ? 'Running...' : 'Run'}
      </button>
    </div>
  );
}

export default SelectEmbeddingModel;


