import React from 'react';

function TriplesTable({ triples }) {
  return (
    <div className="bg-gray-800 bg-opacity-50 backdrop-blur-lg text-white p-3 rounded-lg shadow-md h-full flex flex-col border border-white border-opacity-10">
      <h2 className="text-lg font-bold mb-2 text-center">Triples Found</h2>
      <div className="flex-1 overflow-y-auto overflow-x-auto"> {/* Added horizontal scrolling */}
        <table className="min-w-[90%] table-fixed text-sm mx-auto"> {/* Set table layout to fixed */}
          <thead className="sticky top-0 bg-gray-700 bg-opacity-60">
            <tr>
              <th className="px-2 py-1 text-center w-1/3">Subject</th>
              <th className="px-2 py-1 text-center w-1/3">Predicate</th>
              <th className="px-2 py-1 text-center w-1/3">Object</th>
            </tr>
          </thead>
          <tbody>
            {triples.map((triple, index) => (
              <tr key={index}>
                <td className="border px-2 py-1 text-center">{triple.subject}</td>
                <td className="border px-2 py-1 text-center">{triple.relation}</td>
                <td className="border px-2 py-1 text-center">{triple.object}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default TriplesTable;
