// src/components/UploadPDF.jsx

import React, { useState } from 'react';

function UploadPDF() {
  const [selectedFile, setSelectedFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState('');
  const [uploadedFileName, setUploadedFileName] = useState('');

  const handleFileChange = (event) => {
    setSelectedFile(event.target.files[0]);
    setMessage('');
    setUploadedFileName('');
  };

  const handleFileUpload = async () => {
    if (!selectedFile) {
      setMessage('Please select a file first');
      return;
    }

    setUploading(true);
    setMessage('');

    const formData = new FormData();
    formData.append('file', selectedFile);

    try {
      const response = await fetch('http://127.0.0.1:8000/api/upload-pdf/', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();
      if (response.ok) {
        setMessage('File uploaded and text extracted successfully!');
        setUploadedFileName(selectedFile.name);
        setSelectedFile(null);
      } else {
        setMessage(`Failed to extract text: ${data.error}`);
      }
    } catch (error) {
      setMessage('An error occurred during file upload');
      console.error(error);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="bg-gray-800 bg-opacity-50 backdrop-blur-lg text-white p-4 rounded-lg shadow-md h-48 flex flex-col items-center justify-center border border-white border-opacity-10">
      <h2 className="text-lg font-bold mb-4">Upload PDF</h2>

      {/* File input */}
      {!uploading && (
        <input
          type="file"
          accept="application/pdf"
          onChange={handleFileChange}
          className="mb-4 p-2 border border-gray-300 rounded cursor-pointer text-center w-full"
        />
      )}

      {/* Upload button */}
      {selectedFile && !uploading && (
        <button
          className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
          onClick={handleFileUpload}
        >
          Upload {selectedFile.name}
        </button>
      )}

      {/* Uploading state */}
      {uploading && (
        <div className="flex flex-col items-center">
          <p className="text-sm mb-2">Uploading...</p>
          <div className="loader"></div> {/* Optionally add a loader animation */}
        </div>
      )}

      {/* Message display */}
      {message && <p className="mt-4 text-sm text-center">{message}</p>}

      {/* Uploaded file info */}
      {uploadedFileName && (
        <p className="mt-4 text-sm text-center">
          File "{uploadedFileName}" has been uploaded successfully.
        </p>
      )}
    </div>
  );
}

export default UploadPDF;
