import React from 'react';

function OntologiesTable({ ontologies }) {
  return (
    <div className="bg-gray-800 bg-opacity-50 backdrop-blur-lg text-white p-3 rounded-lg shadow-md h-full flex flex-col border border-white border-opacity-10">
      <h2 className="text-lg font-bold mb-2 text-center">Ontologies Found</h2>
      <div className="flex-1 overflow-y-auto">
        <table className="min-w-[95%] table-auto text-sm mx-auto"> {/* Reduced width and centered */}
          <thead className="sticky top-0 bg-gray-700 bg-opacity-60">
            <tr>
              <th className="px-2 py-1 text-center">Ontology Relations</th>
            </tr>
          </thead>
          <tbody>
            {ontologies.length > 0 ? ontologies.map((ontology, index) => (
              <tr key={index}>
                <td className="border px-2 py-1 text-center">{ontology}</td>
              </tr>
            )) : (
              <tr>
                <td className="border px-2 py-1 text-center">No ontologies found</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default OntologiesTable;
