import React, { useEffect, useState } from 'react';
import ForceGraph2D from 'react-force-graph-2d';

function KnowledgeGraph({ triples }) {
  const [graphData, setGraphData] = useState({ nodes: [], links: [] });

  useEffect(() => {
    console.log('Triples:', triples); // Debugging log
    const nodes = [];
    const links = [];

    triples.forEach(({ subject, relation, object }) => {
      nodes.push({ id: subject });
      nodes.push({ id: object });
      links.push({ source: subject, target: object, label: relation });
    });

    // Remove duplicate nodes
    const uniqueNodes = Array.from(new Set(nodes.map(JSON.stringify))).map(JSON.parse);

    // Set the graph data
    setGraphData({ nodes: uniqueNodes, links: links });

    console.log('Graph Data:', { nodes: uniqueNodes, links: links }); // Debugging log
  }, [triples]);

  return (
    <div className="bg-gray-800 bg-opacity-50 backdrop-blur-lg text-white p-4 rounded-lg shadow-md h-full border border-white border-opacity-10">
      <h2 className="text-lg font-bold mb-2">Knowledge Graph</h2>
      <ForceGraph2D
        graphData={graphData} // Directly pass the graph data
        nodeLabel="id"  // Use the node id as the label
        nodeCanvasObject={(node, ctx, globalScale) => {
          const label = node.id;
          const fontSize = 12 / globalScale;
          ctx.font = `${fontSize}px Sans-Serif`;
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillStyle = 'white';
          ctx.beginPath();
          ctx.arc(node.x, node.y, 8, 0, 2 * Math.PI, false);  // Draw a circle
          ctx.fill();
          ctx.strokeStyle = 'black';
          ctx.stroke();
          ctx.fillStyle = 'black';
          ctx.fillText(label, node.x, node.y);
        }}
        linkDirectionalArrowLength={6}
        linkDirectionalArrowRelPos={1}
        linkLabel={(link) => link.label}
        linkCanvasObjectMode={() => 'after'}
        linkCanvasObject={(link, ctx, globalScale) => {
          const label = link.label;
          if (!label) return;

          const fontSize = 10 / globalScale;
          ctx.font = `${fontSize}px Sans-Serif`;
          ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
          ctx.textAlign = 'center';

          const midPos = {
            x: (link.source.x + link.target.x) / 2,
            y: (link.source.y + link.target.y) / 2,
          };

          ctx.fillText(label, midPos.x, midPos.y);
        }}
        width={window.innerWidth * 0.48}  // Use 48% of the screen width
        height={window.innerHeight * 0.9}  // Use 90% of the screen height
      />
    </div>
  );
}

export default KnowledgeGraph;
