import React, { useState } from 'react';
import '../styles/tailwind.css';
import Header from '../components/Header';
import UploadPDF from '../components/UploadPDF';
import SelectLLMModel from '../components/SelectLLMModel';
import SelectEmbeddingModel from '../components/SelectEmbeddingModel';
import OntologiesTable from '../components/OntologiesTable';
import EntitiesTable from '../components/EntitiesTable';
import TriplesTable from '../components/TriplesTable';
import KnowledgeGraph from '../components/KnowledgeGraph';
import backgroundImage from '../assets/background.jpg';

function UploadPage() {
  const [triples, setTriples] = useState([]);
  const [ontologies, setOntologies] = useState([]);  // State for ontology relations

  return (
    <div
      className="relative flex h-screen"
      style={{
        backgroundImage: `url(${backgroundImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
      }}
    >
      <div className="absolute inset-0 bg-white bg-opacity-20 flex flex-col h-full">
        <Header />
        <div className="flex flex-1 p-4 space-x-4 h-full overflow-hidden">
          <div className="w-1/8 space-y-4 flex flex-col h-full overflow-hidden">
            <UploadPDF />
            <SelectLLMModel setTriples={setTriples} setOntologies={setOntologies} />  {/* Pass setOntologies */}
            <SelectEmbeddingModel />
          </div>

          <div className="w-1/4 h-full flex flex-col space-y-4 overflow-hidden">
            <div className="flex-1 overflow-y-auto">
              <OntologiesTable ontologies={ontologies} />  {/* Pass ontologies to the table */}
            </div>
            <div className="flex-1 overflow-y-auto">
              <EntitiesTable />
            </div>
          </div>

          <div className="w-1/4 h-full overflow-hidden">
            <TriplesTable triples={triples} />
          </div>

          <div className="w-1/2 h-full overflow-hidden">
            <KnowledgeGraph triples={triples} />  {/* Pass triples to the KnowledgeGraph */}
          </div>
        </div>
      </div>
    </div>
  );
}

export default UploadPage;
